detailed_optimizations.code_changes:
1) 将 j=1..ny-1 的主体与边界 j=0 分离，保证主体循环无条件分支：

```c
const DATA_TYPE cex = (DATA_TYPE)0.5;
for (i=0;i<nx;i++) {
  // j=0 不更新（原代码从 1 开始）
  #pragma omp simd
  for (j=1;j<ny;j++)
    ex[i][j] -= cex*(hz[i][j]-hz[i][j-1]);
}
```

2) 若平台对齐敏感，可用 PolyBench 的对齐分配或手动对齐，并在编译器中启用对齐假设（如 `__builtin_assume_aligned`）。

1) 基础向量化：

```c
const DATA_TYPE chz = (DATA_TYPE)0.7;
for (i=0;i<nx-1;i++) {
  #pragma omp simd
  for (j=0;j<ny-1;j++) {
    hz[i][j] -= chz * ( (ex[i][j+1]-ex[i][j]) + (ey[i+1][j]-ey[i][j]) );
  }
}
```

2) 若编译器难以向量化（因潜在别名/对齐），配合 restrict + 对齐假设。

3) 可选：对 ex/ey 的差分先在寄存器中形成，避免重复加载（编译器通常可做，但可通过局部变量显式表达）：

```c
DATA_TYPE dex = ex[i][j+1]-ex[i][j];
DATA_TYPE dey = ey[i+1][j]-ey[i][j];
```

1) 在每个空间循环外层 i 上并行（避免对 j 并行导致过多线程开销）：

```c
#pragma omp parallel
for (t=0;t<tmax;t++) {
  #pragma omp for
  for (j=0;j<ny;j++) ey[0][j]=_fict_[t];

  #pragma omp for collapse(1)
  for (i=1;i<nx;i++) {
    #pragma omp simd
    for (j=0;j<ny;j++) ey[i][j] -= cey*(hz[i][j]-hz[i-1][j]);
  }

  #pragma omp for
  for (i=0;i<nx;i++) {
    #pragma omp simd
    for (j=1;j<ny;j++) ex[i][j] -= cex*(hz[i][j]-hz[i][j-1]);
  }

  #pragma omp for
  for (i=0;i<nx-1;i++) {
    #pragma omp simd
    for (j=0;j<ny-1;j++) hz[i][j] -= chz*((ex[i][j+1]-ex[i][j])+(ey[i+1][j]-ey[i][j]));
  }
}
```

2) NUMA：在 init_array 中用相同的并行策略触发 first-touch（或在 main 中并行初始化 ex/ey/hz）。

对 i/j 做二维分块，使 hz/ex/ey 的相邻行在 LLC 中复用更好（尤其 hz 更新需要 ex[i][j+1]、ey[i+1][j]）：

```c
const int Bi=64, Bj=256; // 需按机器 LLC/带宽调参
for (t=0;t<tmax;t++) {
  for (int ii=1; ii<nx; ii+=Bi)
    for (int jj=0; jj<ny; jj+=Bj) {
      int iend = MIN(ii+Bi, nx);
      int jend = MIN(jj+Bj, ny);
      for (int i=ii;i<iend;i++)
        for (int j=jj;j<jend;j++)
          ey[i][j] -= cey*(hz[i][j]-hz[i-1][j]);
    }
  // ex/hz 同理（注意各自 j 起点/终点）
}
```

并与 OpenMP 结合：对 (ii,jj) 块并行 `#pragma omp for collapse(2)`。
